\begin{proof}    
	From (\ref{fQjQk-2}) and (\ref{fQjQkQl-2}) we get
	\begin{align*}
		\langle Q_j(x_0) P_\gamma(x_0)Q_k(x_0) v,v \rangle &= \langle Q_j(x_1) P_\gamma(x_1)Q_k(x_1) w,w \rangle,\\
		\langle Q_j(x_0) P_\gamma(x_0)Q_k(x_0)P_\gamma(x_0)Q_j(x_0)v,v \rangle &= \langle Q_j(x_1) P_\gamma(x_1)Q_k(x_1)P_\gamma(x_1)Q_j(x_1) w,w \rangle.
	\end{align*}
	That is, 
	\begin{align}
		\sqrt{\gamma^{a_j}(x_0)\gamma^{a_k}(x_0)}v_k\overline{v_j}  
		&= \sqrt{\gamma^{a_j}(x_1)\gamma^{a_k}(x_1)}w_k\overline{w_j},
		\label{ljk} \\
		\gamma^{a_j}(x_0)\gamma^{a_k}(x_0) |v_j|^2 
		&=
		\gamma^{a_j}(x_1)\gamma^{a_k}(x_1)|w_j|^2. \label{ljl}
	\end{align}

	In the case $j=k$, Equation $\ref{ljk}$ reduces to
	\begin{align}
		\gamma^{a_j}(x_0)|v_j |^2  
		&= \gamma^{a_j}(x_1)|w_j|^2.
		\label{ljk1}
	\end{align}


	For $x_0, x_1 \in (0, \infty)$, the values $\gamma^{a_j}(x_0)$ and $\gamma^{a_j}(x_1)$ are different from zero for all $j=1,\dots,n$. Then \eqref{ljk1} implies that $v_j\neq 0$ if and only if $w_j\neq 0$.
	Choose $j$ such that $v_j \neq 0$. 
	Substituting (\ref{ljk1}) in (\ref{ljl}) and reducing, we obtain
	\begin{equation*}\label{gak}
		\gamma^{a_k}(x_0) = \gamma^{a_k}(x_1), \quad \text{ for all }\, k=1,\dots,n.   
	\end{equation*}
	In particular $\gamma^{a_n}(x_0)=\gamma^{a_n}(x_1)$. That is, 
	\begin{align*}
		\int_{2(n-1)x_0}^{\infty}(\ell_0(y))^2 dy&=\int_{2(n-1)x_1}^{\infty}(\ell_0(y))^2dy, 
	\end{align*}
	which implies $x_0=x_1$. 
	From (\ref{ljk}) we get
	$v_k\overline{v_j}=w_k\overline{w_j}\ $ for all $ k=1,\dots,n.$ 
	Thus
	\begin{equation*}\label{razon1}
		\frac{v_k}{w_k}=\frac{\overline{w_j}}{\overline{v_j}},  
	\end{equation*}
	for all $k$ with $v_k\neq 0$. At this point, define $\lambda=\overline{w_j}/\overline{v_j}$, note that $\lambda$ does not depend on $j$.
	Then we can write 
	$v_k=\lambda w_k$  for all  $k=1,\dots,n$, or equivalently
	$v=\lambda w$, where $|\lambda|=1.$
\end{proof}

