	\end{equation*}	
	and
	\begin{equation*}
		(\mathbf{R}^* f)(x,y)= \frac{1}{\sqrt{2\pi}} \int_{\mathbb{R}_+} e^{itx}
		\sqrt{2t}\, \ell_0(2ty)\, f(t) dt, \quad f \in (L_2(\mathbb{R_+}))^n.
	\end{equation*}	

