		&=\left(\left[ \mathbf{R}^* P_\gamma  \mathbf{R}\right]\phi\right)(x,y)\\
		&=\frac{1}{\sqrt{2\pi}} \int_{\mathbb{R}_+} e^{itx}
		\sqrt{2t}\, \ell_0(2ty)\, P_{\gamma}(t)\, (\mathbf{R}\phi)(t)\, dt \\
		&= \frac{1 }{2\pi}  \int_{\mathbb{R_+}} e^{itx}   \int_{\mathbb{R}_+}  \int_{\mathbb{R}}
